@startuml
class "Fruit" {
  [C]
  + show()
  + hide()
}

class "SlidingFruit" {
  [C]
  + show() // animate - slide in
}

class "RollingFruit" {
  [C]
  + show() // animate - roll in
}

class "Banana" {
  [C]
  + hide() // animate - fade out
}

class "Apple" {
  [C]
  + hide() // animate - fade out
}

class "Orange" {
  [C]
  + hide() // animate - slide out
}

Fruit <|-- SlidingFruit
Fruit <|-- RollingFruit
SlidingFruit <|-- Banana
RollingFruit <|-- Apple
RollingFruit <|-- Orange

note right of Fruit
  This is a note.
end note

@enduml
